+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { hasRelationPair } from '../relation/relation';
+import { getStore, hasTrait } from '../trait/trait';
+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import type { Modifier, QueryInstance } from './types';
+
+export function matchesPredicate(world: World, entity: Entity, modifier: Modifier): boolean {
+    const traits = modifier.traits;
+    const values = new Array(traits.length);
+    for (let i = 0; i < traits.length; i++) {
+        const trait = traits[i];
+        if (!hasTrait(world, entity, trait)) return false;
+        values[i] = trait[$internal].get(getEntityId(entity), getStore(world, trait));
+    }
+    return modifier.predicate!(values);
+}
+
+export function checkPredicateFilters(world: World, query: QueryInstance, entity: Entity): boolean {
+    const filters = query.predicateFilters;
+    for (let i = 0; i < filters.length; i++) {
+        const filter = filters[i];
+        if (filter.tracking || filter.or) continue;
+        const matches = matchesPredicate(world, entity, filter.modifier);
+        if (filter.inverted ? matches : !matches) return false;
+    }
+    return true;
+}
+
+export function matchesOrPredicateFilters(world: World, query: QueryInstance, entity: Entity): boolean {
+    for (const filter of query.predicateFilters) {
+        if (filter.or && matchesPredicate(world, entity, filter.modifier)) return true;
+    }
+    return false;
+}
+
+export function initializePredicateStates(world: World, query: QueryInstance, entity: Entity) {
+    for (const filter of query.predicateFilters) {
+        if (!filter.tracking) continue;
+        let states = query.predicateStates.get(filter.modifier);
+        if (!states) query.predicateStates.set(filter.modifier, (states = new Map()));
+        states.set(entity, matchesPredicate(world, entity, filter.modifier));
+    }
+}
+
+export function updatePredicateQueries(world: World, entity: Entity, trait: Trait) {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+    for (const query of instance.predicateQueries) {
+        let shouldAdd = false;
+        for (const filter of query.predicateFilters) {
+            if (!filter.tracking || !filter.modifier.traits.includes(trait)) continue;
+            let states = query.predicateStates.get(filter.modifier);
+            if (!states) query.predicateStates.set(filter.modifier, (states = new Map()));
+            const previous = states.get(entity) ?? false;
+            const current = matchesPredicate(world, entity, filter.modifier);
+            states.set(entity, current);
+            if (
+                (filter.tracking === 'add' && !previous && current) ||
+                (filter.tracking === 'remove' && previous && !current) ||
+                (filter.tracking === 'change' && previous !== current)
+            ) shouldAdd = true;
+        }
+
+        if (shouldAdd && matchesQueryConstraints(world, query, entity)) query.add(entity);
+        else if (!hasTrackingPredicate(query) && matchesQueryConstraints(world, query, entity)) query.add(entity);
+        else if (!hasTrackingPredicate(query)) query.remove(world, entity);
+    }
+}
+
+function hasTrackingPredicate(query: QueryInstance) {
+    return query.predicateFilters.some((filter) => filter.tracking);
+}
+
+function matchesQueryConstraints(world: World, query: QueryInstance, entity: Entity) {
+    if (!query.check(world, entity)) return false;
+    for (const pair of query.relationFilters ?? []) if (!hasRelationPair(world, entity, pair)) return false;
+    return true;
+}
