+import { beforeEach, describe, expect, it } from 'vitest';
+import { createAdded, createChanged, createPredicate, createRemoved, createWorld, Not, Or, relation, trait } from '../src';
+
+const Health = trait({ value: 0 });
+const Speed = trait({ value: 0 });
+const IsTag = trait();
+const Likes = relation();
+
+describe('Predicate query filters', () => {
+    const world = createWorld();
+    world.init();
+
+    beforeEach(() => world.reset());
+
+    it('filters dependency values and does not add them to callback state', () => {
+        const positive = createPredicate([Health], ([health]) => health.value > 0);
+        const entity = world.spawn(Health({ value: 1 }), Speed({ value: 2 }));
+        expect(world.query(positive)).toEqual([entity]);
+        world.query(positive, Speed).readEach(([speed]) => expect(speed.value).toBe(2));
+        entity.set(Health, { value: 0 });
+        expect(world.query(positive)).toEqual([]);
+        entity.set(Health, { value: 3 });
+        expect(world.query(positive)).toEqual([entity]);
+    });
+
+    it('supports Not and Or', () => {
+        const positive = createPredicate([Health], ([health]) => health.value > 0);
+        const a = world.spawn(Health({ value: 0 }));
+        const b = world.spawn(Health({ value: 1 }));
+        const c = world.spawn();
+        expect(world.query(Not(positive))).toEqual([a, c]);
+        expect(world.query(Or(Speed, positive))).toEqual([b]);
+    });
+
+    it('tracks predicate truth transitions', () => {
+        const positive = createPredicate([Health], ([health]) => health.value > 0);
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const entity = world.spawn(Health({ value: 0 }));
+        world.query(Added(positive));
+        world.query(Removed(positive));
+        world.query(Changed(positive));
+        entity.set(Health, { value: 1 });
+        expect(world.query(Added(positive))).toEqual([entity]);
+        expect(world.query(Removed(positive))).toEqual([]);
+        expect(world.query(Changed(positive))).toEqual([entity]);
+        entity.set(Health, { value: 0 });
+        expect(world.query(Removed(positive))).toEqual([entity]);
+        expect(world.query(Changed(positive))).toEqual([entity]);
+    });
+
+    it('rejects tags and relations as dependencies', () => {
+        expect(() => createPredicate([IsTag], () => true)).toThrow('tags');
+        expect(() => createPredicate([Likes as any], () => true)).toThrow('relations');
+    });
+});
