export function setChanged(world: World, entity: Entity, trait: Trait) {
    const data = markChanged(world, entity, trait);
    if (!data) return;
    for (const sub of data.changeSubscriptions) sub(entity);
    updatePredicateQueries(world, entity, trait);
}

export function setPairChanged(world: World, entity: Entity, trait: Trait, target: Entity) {
    const data = markChanged(world, entity, trait);
    if (!data) return;
    for (const sub of data.changeSubscriptions) sub(entity, target);
}

export function checkPredicateFilters(world: World, query: QueryInstance, entity: Entity): boolean {
    const filters = query.predicateFilters;
    for (let i = 0; i < filters.length; i++) {
        const filter = filters[i];
        if (filter.tracking || filter.or) continue;
        const matches = matchesPredicate(world, entity, filter.modifier);
        if (filter.inverted ? matches : !matches) return false;
    }
    return true;
}

export function matchesOrPredicateFilters(world: World, query: QueryInstance, entity: Entity): boolean {
    for (const filter of query.predicateFilters) {
        if (filter.or && matchesPredicate(world, entity, filter.modifier)) return true;
    }
    return false;
}

export function initializePredicateStates(world: World, query: QueryInstance, entity: Entity) {
    for (const filter of query.predicateFilters) {
        if (!filter.tracking) continue;
        let states = query.predicateStates.get(filter.modifier);
        if (!states) query.predicateStates.set(filter.modifier, (states = new Map()));
        states.set(entity, matchesPredicate(world, entity, filter.modifier));
